+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { hasTrait } from '../trait/trait';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import { createModifier } from './modifier';
+import type { PredicateData, PredicateModifier, QueryInstance } from './types';
+import { checkQueryWithRelations } from './utils/check-query-with-relations';
+
+let predicateId = 0;
+
+export function createPredicate<T extends Trait[]>(
+    traits: [...T],
+    predicate: (data: PredicateData<T>) => boolean
+): PredicateModifier<T> {
+    for (const trait of traits) {
+        if (isRelation(trait as never) || trait[$internal].type === 'tag') {
+            throw new Error('Koota: Predicate dependencies must be data traits, not tags or relations.');
+        }
+    }
+    const modifier = createModifier('predicate', ++predicateId, traits) as PredicateModifier<T>;
+    modifier.predicate = predicate;
+    return modifier;
+}
+
+export function isPredicateModifier(value: unknown): value is PredicateModifier {
+    return !!(value as PredicateModifier)?.predicate;
+}
+
+export function matchesPredicate(world: World, entity: Entity, predicate: PredicateModifier): boolean {
+    const data: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        const ctx = trait[$internal];
+        data.push(ctx.get(entity & 0xfffff, world[$internal].traitInstances[trait.id]!.store));
+    }
+    return predicate.predicate(data as PredicateData<any>);
+}
+
+export function matchesQueryPredicates(world: World, entity: Entity, query: QueryInstance): boolean {
+    for (const predicate of query.predicates) if (!matchesPredicate(world, entity, predicate)) return false;
+    for (const predicate of query.notPredicates) if (matchesPredicate(world, entity, predicate)) return false;
+    if (query.orPredicates.length && !query.orPredicates.some((predicate) => matchesPredicate(world, entity, predicate))) return false;
+    return true;
+}
+
+export function reevaluatePredicateQueries(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+    for (const query of instance.predicateQueries) {
+        const previous = query.predicateStates.get(entity) ?? false;
+        const current = matchesQueryPredicates(world, entity, query);
+        query.predicateStates.set(entity, current);
+        if (query.trackingPredicates.length) {
+            const transitioned = query.trackingPredicates.some(({ type }) =>
+                type === 'add' ? !previous && current : type === 'remove' ? previous && !current : previous !== current
+            );
+            const match = transitioned && checkQueryWithRelations(world, query, entity);
+            if (match) query.add(entity);
+            else query.remove(world, entity);
+        } else {
+            const match = checkQueryWithRelations(world, query, entity);
+            if (match) query.add(entity);
+            else query.remove(world, entity);
+        }
+    }
+}
