+
+let predicateId = 0;
+
+export function createPredicate<T extends Trait[]>(traits: [...T], predicate: (data: PredicateData<T>) => boolean): PredicateModifier<T> {
+    for (const trait of traits) {
+        if (isRelation(trait as never) || trait[$internal].type === 'tag') throw new Error('Koota: Predicate dependencies must be data traits, not tags or relations.');
+    }
+    return Object.assign(createModifier('predicate', ++predicateId, traits), { predicate }) as PredicateModifier<T>;
+}
+
+export function isPredicateModifier(value: unknown): value is PredicateModifier {
+    return !!(value as PredicateModifier)?.predicate;
+}
+
+export function matchesPredicate(world: World, entity: Entity, predicate: PredicateModifier): boolean {
+    const values: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        const instance = world[$internal].traitInstances[trait.id]!;
+        values.push(trait[$internal].get(entity & 0xfffff, instance.store));
+    }
+    return predicate.predicate(values as PredicateData<any>);
+}
+
+export function matchesQueryPredicates(world: World, entity: Entity, query: QueryInstance): boolean {
+    return query.predicates.every((p) => matchesPredicate(world, entity, p)) &&
+        query.notPredicates.every((p) => !matchesPredicate(world, entity, p)) &&
+        (!query.orPredicates.length || query.orPredicates.some((p) => matchesPredicate(world, entity, p)));
+}
+
+export function reevaluatePredicateQueries(world: World, entity: Entity, trait: Trait) {
+    for (const query of world[$internal].traitInstances[trait.id]?.predicateQueries ?? []) {
+        query.predicateStates.set(entity, matchesQueryPredicates(world, entity, query));
+        const match = query.check(world, entity);
+        if (match) query.add(entity); else query.remove(world, entity);
+    }
+}
